const body = $input.first().json.body || $input.first().json;
const error_type = body.error_type || body.type || 'unknown';
const message = body.message || body.error || 'No message provided';
const source = body.source || body.workflow || 'unknown';
const user_id = body.user_id || null;
const workspace_id = body.workspace_id || null;
const stack = body.stack || null;
const context = body.context || {};

// Severity classification
const CRITICAL_PATTERNS = ['payment', 'stripe', 'auth', 'rls', 'permission', 'service_role'];
const HIGH_PATTERNS = ['edge_function', 'timeout', 'rate_limit', 'openai', 'anthropic', 'claude'];
const MEDIUM_PATTERNS = ['validation', 'missing_field', 'not_found', 'n8n'];

const lowerMsg = (message + error_type + source).toLowerCase();
let severity = 'low';
if (CRITICAL_PATTERNS.some((p) => lowerMsg.includes(p))) severity = 'critical';
else if (HIGH_PATTERNS.some((p) => lowerMsg.includes(p))) severity = 'high';
else if (MEDIUM_PATTERNS.some((p) => lowerMsg.includes(p))) severity = 'medium';

return [{ json: { error_type, message, source, user_id, workspace_id, stack, context, severity, now: new Date().toISOString() } }];

